from langchain_community.document_loaders import ( TextLoader, PyPDFLoader, WebBaseLoader, DirectoryLoader )
# Load a single PDF pdf_loader = PyPDFLoader("document.pdf")
# Load all .txt files in a directory dir_loader = DirectoryLoader( "./documents", glob="**/*.txt", loader_cls=TextLoader ) documents = dir_loader.load()

from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_core.runnables import RunnablePassthrough

llm = ChatOpenAI(model="gpt-4o", temperature=0)

rag_prompt = ChatPromptTemplate.from_template("""
Answer based on the context below.

Context: {context}

Question: {question}

Answer:""")

def format_docs(docs):
    return "\n\n".join(doc.page_content for doc in docs)

rag_chain = (
    {"context": retriever | format_docs, "question": RunnablePassthrough()}
    | rag_prompt
    | llm
    | StrOutputParser()
)

answer = rag_chain.invoke("What is LangChain?")
